import React, { useEffect, useState } from "react";
import API from "../../api/api";
import { useNavigate } from "react-router-dom";

const formatDate = (d) => d ? new Date(d).toLocaleDateString("en-IN", {
  day: "2-digit", month: "short", year: "numeric"
}) : "";

const MyProjects = () => {
  const navigate = useNavigate();
  const [projects, setProjects]     = useState([]);
  const [submissions, setSubmissions] = useState({}); // project_id → count
  const [loading, setLoading]       = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const res = await API.get("/projects/client");
        const data = res.data || [];
        setProjects(data);

        // Check submissions count for each project
        const subCounts = {};
        await Promise.all(data.map(async (p) => {
          try {
            const r = await API.get(`/submissions/project/${p.id}`);
            subCounts[p.id] = r.data?.length || 0;
          } catch { subCounts[p.id] = 0; }
        }));
        setSubmissions(subCounts);
      } catch (err) { console.error(err); }
      setLoading(false);
    };
    load();
  }, []);

  const statusStyle = (s) => {
    if (s === "closed")      return "bg-red-100 text-red-600";
    if (s === "in-progress") return "bg-yellow-100 text-yellow-700";
    return "bg-green-100 text-green-600";
  };

  if (loading) return <div className="text-center py-16 text-gray-400">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-5xl mx-auto">

        <div className="flex justify-between items-center mb-6">
          <div>
            <h1 className="text-2xl font-bold text-gray-800">My Projects</h1>
            <p className="text-gray-500 text-sm mt-1">{projects.length} project{projects.length !== 1 ? "s" : ""} posted</p>
          </div>
          <button onClick={() => navigate("/client/post-project")}
            className="bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition">
            + Post New Project
          </button>
        </div>

        {projects.length === 0 ? (
          <div className="bg-white rounded-xl p-12 text-center shadow-sm border border-gray-100">
            <div className="text-5xl mb-3">📁</div>
            <p className="text-gray-500 mb-4">No projects yet.</p>
            <button onClick={() => navigate("/client/post-project")}
              className="bg-teal-600 text-white px-5 py-2 rounded-lg text-sm font-medium">
              Post Your First Project
            </button>
          </div>
        ) : (
          <div className="space-y-4">
            {projects.map((p) => (
              <div key={p.id} className="bg-white rounded-xl shadow-sm border border-gray-100 p-5 hover:shadow-md transition">
                <div className="flex justify-between items-start mb-3">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-3 mb-1">
                      <h3 className="font-bold text-gray-800 text-lg truncate">{p.title}</h3>
                      <span className={`px-2 py-0.5 rounded-full text-xs font-semibold capitalize flex-shrink-0 ${statusStyle(p.status)}`}>
                        {p.status || "Open"}
                      </span>
                    </div>
                    <p className="text-gray-500 text-sm truncate">{p.description}</p>
                  </div>
                </div>

                {/* META */}
                <div className="flex flex-wrap gap-4 text-sm text-gray-500 mb-4">
                  <span>💰 <strong className="text-gray-700">₹{p.budget}</strong></span>
                  {p.deadline && <span>📅 {formatDate(p.deadline)}</span>}
                  {p.category && (
                    <span className="text-teal-600 font-medium capitalize">{p.category.replace(/-/g, " ")}</span>
                  )}
                  {p.skills && p.skills.split(",").slice(0, 3).map((s, i) => (
                    <span key={i} className="bg-gray-100 text-gray-600 px-2 py-0.5 rounded text-xs">{s.trim()}</span>
                  ))}
                </div>

                {/* BUTTONS */}
                <div className="flex gap-3 pt-3 border-t border-gray-100">
                  <button onClick={() => navigate(`/client/projects/${p.id}/proposals`)}
                    className="bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition">
                    View Proposals →
                  </button>
                  <button onClick={() => navigate(`/client/projects/${p.id}/submissions`)}
                    className="relative bg-gray-100 hover:bg-gray-200 text-gray-700 px-4 py-2 rounded-lg text-sm font-medium transition flex items-center gap-2">
                    📤 View Submissions
                    {submissions[p.id] > 0 && (
                      <span className="bg-teal-600 text-white text-xs w-5 h-5 rounded-full flex items-center justify-center font-bold">
                        {submissions[p.id]}
                      </span>
                    )}
                  </button>
                  <button onClick={() => navigate(`/client/projects/${p.id}/milestones`)}
                    className="bg-gray-100 hover:bg-gray-200 text-gray-700 px-4 py-2 rounded-lg text-sm font-medium transition">
                    🎯 Milestones
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default MyProjects;
